fn main() {
    let data = vec![Some(1), Some(2), None, Some(3)];
    let result: Vec<i32> = data.iter()
        .map(|x| x.unwrap())
        .collect();
    println!("{:?}", result);
}

fixed_code:
fn main() {
    let data = vec![Some(1), Some(2), None, Some(3)];
    let result: Vec<i32> = data.into_iter()
        .filter_map(|x| x)
        .collect();
    println!("{:?}", result);
}

